{"content":"1: package parser
2: 
3: import (
4: 	"encoding/json"
5: 
6: 	v2 "github.com/future-architect/vuls/contrib/trivy/parser/v2"
7: 	"github.com/future-architect/vuls/models"
8: 	"golang.org/x/xerrors"
9: )
10: 
11: // Parser is a parser interface
12: type Parser interface {
13: 	Parse(vulnJSON []byte) (result *models.ScanResult, err error)
14: }
15: 
16: // Report is used for judgeing the scheme version of trivy
17: type Report struct {
18: 	SchemaVersion int `json:",omitempty"`
19: }
20: 
21: // NewParser make a parser for the schema version of trivy
22: func NewParser(vulnJSON []byte) (Parser, error) {
23: 	r := Report{}
24: 	if err := json.Unmarshal(vulnJSON, &r); err != nil {
25: 		return nil, xerrors.Errorf("Failed to parse JSON. Please use the latest version of trivy, trivy-to-vuls and future-vuls")
26: 	}
27: 	switch r.SchemaVersion {
28: 	case 2:
29: 		return v2.ParserV2{}, nil
30: 	default:
31: 		return nil, xerrors.Errorf("Failed to parse trivy json. SchemeVersion %d is not supported yet. Please contact support", r.SchemaVersion)
32: 	}
33: }
