{"content":"1: package pkg
2: 
3: import (
4: 	"sort"
5: 	"time"
6: 
7: 	"github.com/aquasecurity/trivy/pkg/fanal/analyzer/os"
8: 	"github.com/aquasecurity/trivy/pkg/types"
9: 
10: 	"github.com/future-architect/vuls/models"
11: )
12: 
13: // Convert :
14: func Convert(results types.Results) (result *models.ScanResult, err error) {
15: 	scanResult := &models.ScanResult{
16: 		JSONVersion: models.JSONVersion,
17: 		ScannedCves: models.VulnInfos{},
18: 	}
19: 
20: 	pkgs := models.Packages{}
21: 	srcPkgs := models.SrcPackages{}
22: 	vulnInfos := models.VulnInfos{}
23: 	uniqueLibraryScannerPaths := map[string]models.LibraryScanner{}
24: 	for _, trivyResult := range results {
25: 		for _, vuln := range trivyResult.Vulnerabilities {
26: 			if _, ok := vulnInfos[vuln.VulnerabilityID]; !ok {
27: 				vulnInfos[vuln.VulnerabilityID] = models.VulnInfo{
28: 					CveID: vuln.VulnerabilityID,
29: 					Confidences: models.Confidences{
30: 						{
31: 							Score:           100,
32: 							DetectionMethod: models.TrivyMatchStr,
33: 						},
34: 					},
35: 					AffectedPackages: models.PackageFixStatuses{},
36: 					CveContents:      models.CveContents{},
37: 					LibraryFixedIns:  models.LibraryFixedIns{},
38: 					// VulnType : "",
39: 				}
40: 			}
41: 			vulnInfo := vulnInfos[vuln.VulnerabilityID]
42: 			var notFixedYet bool
43: 			fixState := ""
44: 			if len(vuln.FixedVersion) == 0 {
45: 				notFixedYet = true
46: 				fixState = "Affected"
47: 			}
48: 			var references models.References
49: 			for _, reference := range vuln.References {
50: 				references = append(references, models.Reference{
51: 					Source: "trivy",
52: 					Link:   reference,
53: 				})
54: 			}
55: 
56: 			sort.Slice(references, func(i, j int) bool {
57: 				return references[i].Link < references[j].Link
58: 			})
59: 
60: 			var published time.Time
61: 			if vuln.PublishedDate != nil {
62: 				published = *vuln.PublishedDate
63: 			}
64: 
65: 			var lastModified time.Time
66: 			if vuln.LastModifiedDate != nil {
67: 				lastModified = *vuln.LastModifiedDate
68: 			}
69: 
70: 			vulnInfo.CveContents = models.CveContents{
71: 				models.Trivy: []models.CveContent{{
72: 					Cvss3Severity: vuln.Severity,
73: 					References:    references,
74: 					Title:         vuln.Title,
75: 					Summary:       vuln.Description,
76: 					Published:     published,
77: 					LastModified:  lastModified,
78: 				}},
79: 			}
80: 			// do only if image type is Vuln
81: 			if isTrivySupportedOS(trivyResult.Type) {
82: 				pkgs[vuln.PkgName] = models.Package{
83: 					Name:    vuln.PkgName,
84: 					Version: vuln.InstalledVersion,
85: 				}
86: 				vulnInfo.AffectedPackages = append(vulnInfo.AffectedPackages, models.PackageFixStatus{
87: 					Name:        vuln.PkgName,
88: 					NotFixedYet: notFixedYet,
89: 					FixState:    fixState,
90: 					FixedIn:     vuln.FixedVersion,
91: 				})
92: 			} else {
93: 				vulnInfo.LibraryFixedIns = append(vulnInfo.LibraryFixedIns, models.LibraryFixedIn{
94: 					Key:     trivyResult.Type,
95: 					Name:    vuln.PkgName,
96: 					Path:    trivyResult.Target,
97: 					FixedIn: vuln.FixedVersion,
98: 				})
99: 				libScanner := uniqueLibraryScannerPaths[trivyResult.Target]
100: 				libScanner.Type = trivyResult.Type
101: 				libScanner.Libs = append(libScanner.Libs, models.Library{
102: 					Name:     vuln.PkgName,
103: 					Version:  vuln.InstalledVersion,
104: 					FilePath: vuln.PkgPath,
105: 				})
106: 				uniqueLibraryScannerPaths[trivyResult.Target] = libScanner
107: 			}
108: 			vulnInfos[vuln.VulnerabilityID] = vulnInfo
109: 		}
110: 
111: 		// --list-all-pkgs flg of trivy will output all installed packages, so collect them.
112: 		if trivyResult.Class == types.ClassOSPkg {
113: 			for _, p := range trivyResult.Packages {
114: 				pkgs[p.Name] = models.Package{
115: 					Name:    p.Name,
116: 					Version: p.Version,
117: 				}
118: 				if p.Name != p.SrcName {
119: 					if v, ok := srcPkgs[p.SrcName]; !ok {
120: 						srcPkgs[p.SrcName] = models.SrcPackage{
121: 							Name:        p.SrcName,
122: 							Version:     p.SrcVersion,
123: 							BinaryNames: []string{p.Name},
124: 						}
125: 					} else {
126: 						v.AddBinaryName(p.Name)
127: 						srcPkgs[p.SrcName] = v
128: 					}
129: 				}
130: 			}
131: 		} else if trivyResult.Class == types.ClassLangPkg {
132: 			libScanner := uniqueLibraryScannerPaths[trivyResult.Target]
133: 			libScanner.Type = trivyResult.Type
134: 			for _, p := range trivyResult.Packages {
135: 				libScanner.Libs = append(libScanner.Libs, models.Library{
136: 					Name:     p.Name,
137: 					Version:  p.Version,
138: 					FilePath: p.FilePath,
139: 				})
140: 			}
141: 			uniqueLibraryScannerPaths[trivyResult.Target] = libScanner
142: 		}
143: 	}
144: 
145: 	// flatten and unique libraries
146: 	libraryScanners := make([]models.LibraryScanner, 0, len(uniqueLibraryScannerPaths))
147: 	for path, v := range uniqueLibraryScannerPaths {
148: 		uniqueLibrary := map[string]models.Library{}
149: 		for _, lib := range v.Libs {
150: 			uniqueLibrary[lib.Name+lib.Version] = lib
151: 		}
152: 
153: 		var libraries []models.Library
154: 		for _, library := range uniqueLibrary {
155: 			libraries = append(libraries, library)
156: 		}
157: 
158: 		sort.Slice(libraries, func(i, j int) bool {
159: 			return libraries[i].Name < libraries[j].Name
160: 		})
161: 
162: 		libscanner := models.LibraryScanner{
163: 			Type:         v.Type,
164: 			LockfilePath: path,
165: 			Libs:         libraries,
166: 		}
167: 		libraryScanners = append(libraryScanners, libscanner)
168: 	}
169: 	sort.Slice(libraryScanners, func(i, j int) bool {
170: 		return libraryScanners[i].LockfilePath < libraryScanners[j].LockfilePath
171: 	})
172: 	scanResult.ScannedCves = vulnInfos
173: 	scanResult.Packages = pkgs
174: 	scanResult.SrcPackages = srcPkgs
175: 	scanResult.LibraryScanners = libraryScanners
176: 	return scanResult, nil
177: }
