179: func isTrivySupportedOS(family string) bool {
180: 	supportedFamilies := map[string]struct{}{
181: 		os.RedHat:             {},
182: 		os.Debian:             {},
183: 		os.Ubuntu:             {},
184: 		os.CentOS:             {},
185: 		os.Rocky:              {},
186: 		os.Alma:               {},
187: 		os.Fedora:             {},
188: 		os.Amazon:             {},
189: 		os.Oracle:             {},
190: 		os.Windows:            {},
191: 		os.OpenSUSE:           {},
192: 		os.OpenSUSELeap:       {},
193: 		os.OpenSUSETumbleweed: {},
194: 		os.SLES:               {},
195: 		os.Photon:             {},
196: 		os.Alpine:             {},
197: 	}
198: 	_, ok := supportedFamilies[family]
199: 	return ok
200: }
