4: package detector
5: 
6: import (
7: 	"context"
8: 
9: 	trivydb "github.com/aquasecurity/trivy-db/pkg/db"
10: 	"github.com/aquasecurity/trivy-db/pkg/metadata"
11: 	"github.com/aquasecurity/trivy/pkg/db"
12: 	"github.com/aquasecurity/trivy/pkg/log"
13: 	"golang.org/x/xerrors"
14: 
