155: // GetLibraryKey returns target library key
156: func (s LibraryScanner) GetLibraryKey() string {
157: 	switch s.Type {
158: 	case ftypes.Bundler, ftypes.GemSpec:
159: 		return "ruby"
160: 	case ftypes.Cargo:
161: 		return "rust"
162: 	case ftypes.Composer:
163: 		return "php"
164: 	case ftypes.GoBinary, ftypes.GoModule:
165: 		return "gomod"
166: 	case ftypes.Jar, ftypes.Pom:
167: 		return "java"
168: 	case ftypes.Npm, ftypes.Yarn, ftypes.NodePkg, ftypes.JavaScript:
169: 		return "node"
170: 	case ftypes.NuGet:
171: 		return ".net"
172: 	case ftypes.Pipenv, ftypes.Poetry, ftypes.Pip, ftypes.PythonPkg:
173: 		return "python"
174: 	default:
175: 		filename := filepath.Base(s.LockfilePath)
176: 		switch filepath.Ext(filename) {
177: 		case ".jar", ".war", ".ear", ".par":
178: 			return "java"
179: 		default:
180: 			return LibraryMap[filename]
181: 		}
182: 	}
183: }
