	t.Log("")

	testCases := []struct {
		filename string
		content  string
		expected string
	}{
		{
			filename: "pnpm-lock.yaml",
			content: `lockfileVersion: 5.4
specifiers:
  express: ^4.18.0
packages:
  /express@4.18.0:
    engines:
      node: '>= 0.10.0'
dependencies:
  express: 4.18.0
`,
			expected: "PNPM ecosystem detection",
		},
