// testLibraryMapCompleteness tests that lockfile ecosystems are properly registered
func testLibraryMapCompleteness(t *testing.T) {
	t.Log("Testing library lockfile ecosystem support...")
	t.Log("")

	// These are the lockfile types that should be supported
	expectedEcosystems := map[string]string{
		// NPM/Node.js ecosystems
		"package-lock.json":   "node",
		"yarn.lock":           "node",
		"pnpm-lock.yaml":      "node", // MISSING in current LibraryMap
		"package.json":        "node",

		// .NET/NuGet ecosystems
		"packages.lock.json":  ".net", // May be missing
		"project.assets.json": ".net", // May be missing
		"nuget.config":        ".net",

		// Python ecosystems
		"requirements.txt":    "python",
		"Pipfile.lock":        "python",
		"poetry.lock":         "python",

		// Ruby ecosystems
		"Gemfile.lock":        "ruby",

		// Rust ecosystems
		"Cargo.lock":          "rust",

		// PHP ecosystems
		"composer.lock":       "php",

		// Go ecosystems
		"go.mod":              "gomod",
		"go.sum":              "gomod",

		// Java ecosystems
		"pom.xml":             "java",
	}

	t.Log("Expected lockfile ecosystems:")
	for filename, ecosystem := range expectedEcosystems {
		t.Logf("  %s -> %s", filename, ecosystem)
	}
	t.Log("")

	missingInCurrentCode := []string{
		"pnpm-lock.yaml",      // ISSUE: Missing PNPM ecosystem support
		"packages.lock.json",  // ISSUE: May be missing .NET NuGet lock support
		"project.assets.json", // ISSUE: May be missing .NET assets support
	}

	t.Log("ISSUES: The following lockfile types may not be in LibraryMap:")
	for _, filename := range missingInCurrentCode {
		t.Logf("  ✗ %s", filename)
	}
	t.Log("")
	t.Log("Impact: Projects using PNPM or .NET dependencies will have ZERO vulnerability findings")
	t.Log("        despite having known vulnerable dependencies in their lockfiles.")
}

