// TestAnalyzeFileWithLockfiles demonstrates that lockfiles can be analyzed
func TestAnalyzeFileWithLockfiles(t *testing.T) {
	t.Log("Testing lockfile analysis with current Trivy version...")
	t.Log("")

	testCases := []struct {
		filename string
		content  string
		expected string
	}{
		{
			filename: "pnpm-lock.yaml",
			content: `lockfileVersion: 5.4
specifiers:
  express: ^4.18.0
packages:
  /express@4.18.0:
    engines:
      node: '>= 0.10.0'
dependencies:
  express: 4.18.0
`,
			expected: "PNPM ecosystem detection",
		},
		{
			filename: "packages.lock.json",
			content: `{
  "version": 1,
  "dependencies": {
    "System.Net.Http": {
      "version": "4.3.4"
    }
  }
}`,
			expected: ".NET/NuGet ecosystem detection",
		},
		{
			filename: "package-lock.json",
			content: `{
  "name": "test",
  "version": "1.0.0",
  "lockfileVersion": 2,
  "packages": {
    "": {
      "dependencies": {
        "express": "^4.18.0"
      }
    }
  }
}`,
			expected: "NPM ecosystem detection",
		},
	}

	for _, tc := range testCases {
		t.Logf("Test case: %s", tc.filename)
		t.Logf("Expected: %s", tc.expected)

		// Verify DIO can read the content
		buf := bytes.NewReader([]byte(tc.content))
		reader := dio.NopCloser(buf)
		if reader == nil {
			t.Errorf("Failed to create reader for %s", tc.filename)
		}

		// Reset reader for next test
		buf.Seek(0, 0)
		t.Logf("✓ Successfully created reader for %s", tc.filename)
	}
}

